type ContactInfoFormState = {
  emails: ContactPointRow[]
  phones: ContactPointRow[]
  addresses: ContactAddressRow[]
}

function toText(value: unknown): string {
  if (!value) return ''
  if (typeof value === 'string') return value
  if (typeof value === 'object' && 'value' in (value as Record<string, unknown>)) {
    const v = (value as { value?: unknown }).value
    return typeof v === 'string' ? v : ''
  }
  return ''
}

function toTypeLabel(value: unknown): string {
  const raw = toText(value).trim()
  if (!raw) return ''
  const withoutAngles = raw.replace(/^<|>$/g, '')
  const hashParts = withoutAngles.split('#')
  const lastByHash = hashParts[hashParts.length - 1]
  const slashParts = lastByHash.split('/')
  return slashParts[slashParts.length - 1]
}

function sanitizeTextValue(value: string): string {
  return value
    .replace(/[\u0000-\u001F\u007F]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
}

function sanitizeEmailValue(value: string): string {
  return sanitizeTextValue(value).replace(/\s+/g, '').toLowerCase()
}

function sanitizePhoneLocalValue(value: string): string {
  return sanitizeTextValue(value).replace(/[^0-9()\-\s.]/g, '')
}

function sanitizeAddressFieldValue(value: string): string {
  return sanitizeTextValue(value)
}

/* The following 3 functions were generated by AI Model: GPT-5.3-Codex  */
/* Prompt: can you have summarizeRowOps check all fields of address */
function hasNonEmptyText(value: string | undefined): boolean {
  return Boolean(value && value.trim() !== '')
}

function isContactPointRow(row: ContactPointRow | ContactAddressRow): row is ContactPointRow {
  return 'value' in row
}

function rowHasContent(row: ContactPointRow | ContactAddressRow): boolean {
  if (isContactPointRow(row)) {
    return hasNonEmptyText(row.value)
  }

  return [
    row.streetAddress,
    row.locality,
    row.region,
    row.postalCode,
    row.countryName
  ].some(hasNonEmptyText)
}

function toFormState(contactInfo: ContactInfo): ContactInfoFormState {
  const emails = (contactInfo.emails || [])
    .map((email) => ({
      value: sanitizeEmailValue(toText(email.valueNode).replace(/^mailto:/i, '')),
      type: toTypeLabel(email.type),
      entryNode: toText(email.entryNode),
      status: toText(email.entryNode) ? 'existing' as const : 'new' as const
    }))
    .filter((email) => Boolean(email.value || email.entryNode || email.type))

  const phones = (contactInfo.phones || [])
    .map((phone) => ({
      value: sanitizeTextValue(toText(phone.valueNode).replace(/^tel:/i, '')),
      type: toTypeLabel(phone.type),
      entryNode: toText(phone.entryNode),
      status: 'existing' as const
    }))
    .filter((phone) => Boolean(phone.value))
  const addresses = (contactInfo.addresses || [])
    .map((address) => ({
      streetAddress: sanitizeAddressFieldValue(toText(address.streetAddress)),
      locality: sanitizeAddressFieldValue(toText(address.locality)),
      region: sanitizeAddressFieldValue(toText(address.region)),
      postalCode: sanitizeAddressFieldValue(toText(address.postalCode)),
      countryName: sanitizeAddressFieldValue(toText(address.countryName)),
      type: toTypeLabel(address.type),
      entryNode: toText(address.entryNode),
      status: toText(address.entryNode) ? 'existing' as const : 'new' as const
    }))
    .filter((address) => rowHasContent(address) || Boolean(address.entryNode || address.type))

  return {
    emails: emails.length ? emails : [{ value: '', type: '', entryNode: '', status: 'new' }],
    phones: phones.length ? phones : [{ value: '', type: '', entryNode: '', status: 'new' }],
    addresses: addresses.length
      ? addresses
      : [{ streetAddress: '', locality: '', region: '', postalCode: '', countryName: '', type: '', entryNode: '', status: 'new' }]
  }
}

function summarizeRowOps<T extends ContactPointRow | ContactAddressRow>(rows: T[]) {
  const create = rows.filter((row) => row.status === 'new' && rowHasContent(row))
  const update = rows.filter((row) => row.status === 'modified' && rowHasContent(row))
  const remove = rows.filter((row) => row.status === 'deleted')
  return { create, update, remove }
}

function applyPointRowValueChange(row: ContactPointRow, nextValue: string) {
  const trimmed = nextValue.trim()

  if (trimmed === '') {
    row.value = ''
    row.status = row.entryNode ? 'deleted' : 'new'
    return
  }

  row.value = nextValue

  if (row.entryNode) {
    row.status = row.status === 'existing' || row.status === 'deleted' ? 'modified' : row.status
    return
  }

  row.status = 'new'
}

function applyRowTypeChange(row: ContactPointRow | ContactAddressRow, nextValue: string) {
  row.type = nextValue.trim()

  if (row.entryNode) {
    row.status = row.status === 'existing' || row.status === 'deleted' ? 'modified' : row.status
    return
  }

  row.status = 'new'
}

type ContactAddressEditableField =
  | 'streetAddress'
  | 'locality'
  | 'region'
  | 'postalCode'
  | 'countryName'

/* The following function was generated by AI Model: GPT-5.3-Codex  */
/* Prompt: can you have applyAddressFieldChange update the row status based on whether any fields have content */  
function applyAddressFieldChange(
  row: ContactAddressRow,
  field: ContactAddressEditableField,
  nextValue: string
) {
  row[field] = nextValue

  if (!rowHasContent(row)) {
    row.status = row.entryNode ? 'deleted' : 'new'
    return
  }

  if (row.entryNode) {
    row.status = row.status === 'existing' || row.status === 'deleted' ? 'modified' : row.status
    return
  }

  row.status = 'new'
}

type ContactPhoneInputRowProps = {
  phones: ContactPointRow[]
  index: number
  displayIndex: number
  onDelete: () => void
}

type ContactEmailInputRowProps = {
  emails: ContactPointRow[]
  index: number
  displayIndex: number
  onDelete: () => void
}

type ContactAddressInputRowProps = {
  addresses: ContactAddressRow[]
  index: number
  displayIndex: number
  onDelete: () => void
}

function deleteRow<T extends ContactPointRow | ContactAddressRow>(rows: T[], index: number) {
  const row = rows[index]
  if (!row) return

  if (row.entryNode) {
    row.status = 'deleted'
    return
  }

  rows.splice(index, 1)
}
function renderCountryPrefixSelect(
  name: string,
  value: string,
  label: string,
  onChange: (event: Event) => void
) {
  return html`
    <label class="phonePrefixField" aria-label=${label}>
      <select class="phonePrefixSelect" name=${name} .value=${value} @change=${onChange}>
        ${COUNTRY_PREFIX_OPTIONS.map((option) => html`
          <option value=${option.dialCode}>
            ${countryCodeToFlag(option.iso2)} ${option.dialCode}
          </option>
        `)}
      </select>
    </label>
  `
}

function renderContactPhoneInputRow({
  phones,
  index,
  displayIndex,
  onDelete
}: ContactPhoneInputRowProps) {
  const phoneRow = phones[index]
  const label = `Phone Number ${displayIndex + 1}`
  const countryCodeLabel = `Country Calling Code ${displayIndex + 1}`
  const typeLabel = `Phone Type ${displayIndex + 1}`
  const prefixInputName = `phone-prefix-${index}`
  const inputName = `phone-value-${index}`
  const typeInputName = `phone-type-${index}`
  const splitValue = splitPhoneValue(phoneRow?.value || '')
  let selectedDialCode = splitValue.dialCode

  const handleValueInput = (e: Event) => {
    const target = e.target as HTMLInputElement
    const nextValue = sanitizePhoneLocalValue(target.value)
    if (phones[index]) {
      applyPointRowValueChange(phones[index], combinePhoneValue(selectedDialCode, nextValue))
    }
  }

  const handleCountryCodeInput = (e: Event) => {
    const target = e.target as HTMLSelectElement
    selectedDialCode = target.value

    if (phones[index]) {
      const localNumber = splitPhoneValue(phones[index].value).localNumber
      applyPointRowValueChange(phones[index], combinePhoneValue(selectedDialCode, localNumber))
    }
  }

  const handleTypeInput = (e: Event) => {
    const target = e.target as HTMLInputElement
    const nextType = target.value
    if (phones[index]) {
      applyRowTypeChange(phones[index], nextType)
    }
  }

  const handleDelete = (event: Event) => {
    event.preventDefault()
    onDelete()
  }

  return html`
    <div class="contactInputRow">
      <div class="contactInputValueRow phoneCompositeRow">
        ${renderCountryPrefixSelect(prefixInputName, selectedDialCode, countryCodeLabel, handleCountryCodeInput)}
        <span class="phoneCompositeDivider" aria-hidden="true">|</span>
        <label aria-label=${label} class="phoneLocalField">
          <input
            class="phoneLocalInput"
            type="tel"
            name=${inputName}
            .value=${splitValue.localNumber}
            data-contact-field="value"
            data-entry-node=${phoneRow?.entryNode || ''}
            data-row-status=${phoneRow?.status || 'n/a'}
            placeholder="Phone Number"
            autocomplete="tel-national"
            inputmode="tel"
            @input=${handleValueInput}
          />
        </label>
      </div>
      <label aria-label=${typeLabel} class="contactInputTypeRow phoneTypeRow">
        <select name=${typeInputName} id="phone-type-select-${inputName}" @change=${handleTypeInput} .value=${phoneRow?.type || ''}>
          <option value="Home">Mobile</option>
          <option value="Home">Home</option>
          <option value="Work">Work</option>
          <option value="Other">Other</option>
        </select>
      </label>
      <div class="contactInputActions">
        <button
          type="button"
          class="deleteEntryButton"
          aria-label=${`Delete phone number ${displayIndex + 1}`}
          title="Delete entry"
          @click=${handleDelete}
        >
          <svg class="deleteEntryIcon" viewBox="0 0 24 24" aria-hidden="true" focusable="false">
            <path d="M9 3h6l1 2h4v2H4V5h4l1-2zm-1 6h2v9H8V9zm6 0h2v9h-2V9zM6 9h12l-1 12H7L6 9z" />
          </svg>
        </button>
      </div>
    </div>
  `
}

function renderContactInfoPhoneSection(phones: ContactPointRow[], onAddRow: () => void) {
  const createNewRow = (event: Event) => {
    event.preventDefault()
    phones.push({ value: '', type: '', entryNode: '', status: 'new' })
    onAddRow()
  }

  const visiblePhones = phones
    .map((phone, index) => ({ phone, index }))
    .filter(({ phone }) => phone.status !== 'deleted')

  return html`
    <section 
      aria-labelledby="phone-numbers-heading" 
      class="contactsEditSection section-bg">
      <header class="sectionHeader">
        <h4 id="phone-numbers-heading" tabindex="-1">
          <span class="sectionTitleIcon" aria-hidden="true">&#9742;</span>
          Phone Numbers
        </h4>
        <button
          type="button"
          class="actionButton"
          aria-label="Add another phone number"
          @click=${createNewRow}
        >
          + Add More
        </button>
      </header>
      <fieldset>
        <legend class="sr-only">Phone number entries</legend>
        ${visiblePhones.map(({ index }, displayIndex) => renderContactPhoneInputRow({
          phones,
          index,
          displayIndex,
          onDelete: () => {
            deleteRow(phones, index)
            onAddRow()
          }
        }))}
      </fieldset>
    </section>
  `
}

