function renderContactInfoEditTemplate(form: HTMLFormElement, formState: ContactInfoFormState) {
  const rerender = () => renderContactInfoEditTemplate(form, formState)


  render(html`
    ${renderContactInfoPhoneSection(formState.phones, rerender)}
    ${renderContactInfoEmailSection(formState.emails, rerender)}
    ${renderContactInfoAddressSection(formState.addresses, rerender)}
  `, form)
}

function createContactInfoEditForm(contactInfo: ContactInfo) {
  const form = document.createElement('form')
  form.classList.add('section-edit-form')

  const formState = toFormState(contactInfo)
  renderContactInfoEditTemplate(form, formState)

  return { form, formState }
}


export async function createContactInfoEditDialog(
  event: Event,
  store: LiveStore,
  subject: NamedNode,
  contactInfo: ContactInfo,
  viewerMode: ViewerMode
) {
  const dom = (event.currentTarget as HTMLElement | null)?.ownerDocument || document
  const { form, formState } = createContactInfoEditForm(contactInfo)

  const result = await openInputDialog({
    title: 'Edit More Contacts',
    dom,
    form,
    submitLabel: 'Save Changes',
    cancelLabel: 'Cancel'
  })

  if (!result) return

  if (viewerMode !== 'owner') {
    await alertDialog('You need to log in as the profile owner to save contact updates.', 'Login Required', dom)
    return
  }

 const plan: ContactMutationPlan = {
  phoneOps: summarizeRowOps(formState.phones),
  emailOps: summarizeRowOps(formState.emails),
  addressOps: summarizeRowOps(formState.addresses)
}

  // Save wiring is section-specific and can be added when mutation logic is ready.
  console.log('Contact edit values', result)
  console.log('Pending phone operations', plan.phoneOps)
  console.log('Pending email operations', plan.emailOps)
  console.log('Pending address operations', plan.addressOps)

  try {
    await processContactInfoMutations(store, subject, plan)

    const view = dom.defaultView
    if (view) {
      view.location.reload()
    }
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error)
    await alertDialog(`Could not save contact updates. ${message}`, 'Save Failed', dom)
  }
}

